mapper.insert:
insert into patient
case_no, name, gender, height, birthday, phone, address, create_time, create_by
#{caseNo}, #{name}, #{gender}, #{height}, #{birthday}, #{phone}, #{address}, sysdate(), #{createBy}

mapper.update:
update patient
case_no = #{caseNo}, name = #{name}, gender = #{gender}, height = #{height}, birthday = #{birthday}, phone = #{phone}, id_card = #{idCard}, address = #{address}, update_time = sysdate()
where id = #{id}

mapper.select:
select 
from patient

    del_flag = 0 and is_report = 0
    and case_no like concat('%',#{caseNo},'%')
    and name like concat('%',#{name},'%')
    and gender = #{gender}
    and height = #{height}
    and birthday = #{birthday}
    and phone like concat('%',#{phone},'%')
    and id_card like concat('%',#{idCard},'%')
    and address like concat('%',#{address},'%')

        and create_time >= #{beginCreateTime}


        and create_time <= #{endCreateTime}


order by id desc
